// Validate required fields before hitting Claude
const body = $input.first().json.body || $input.first().json;
const required = ['account_name', 'arr', 'renewal_horizon_days', 'raw_feedback'];
const missing = required.filter(f => !body[f] && body[f] !== 0);

if (missing.length > 0) {
  throw new Error(`Missing required fields: ${missing.join(', ')}`);
}

// Normalize arr — handle '$500K', '500,000', '0.5M' formats
let arr = body.arr;
if (typeof arr === 'string') {
  arr = arr.replace(/[$,]/g, '');
  if (arr.toLowerCase().includes('k')) arr = parseFloat(arr) * 1000;
  else if (arr.toLowerCase().includes('m')) arr = parseFloat(arr) * 1000000;
  else arr = parseFloat(arr);
}

// Normalize days
let days = parseInt(body.renewal_horizon_days, 10);
if (isNaN(days)) days = 180; // safe default

return [{
  json: {
    account_name: String(body.account_name).trim(),
    arr: Math.round(arr),
    renewal_horizon_days: days,
    raw_feedback: String(body.raw_feedback).trim(),
    source_channel: body.source_channel || 'manual_form',
    received_at: new Date().toISOString()
  }
}];

// Read Claude's tool_use block — no text parsing, no markdown-fence stripping.
const claudeResponse = $input.first().json;
if (claudeResponse.stop_reason !== 'tool_use') {
  throw new Error(`Expected stop_reason 'tool_use', got '${claudeResponse.stop_reason}'. Check tool_choice is set on the Claude node.`);
}

const toolUseBlock = (claudeResponse.content || []).find(b => b.type === 'tool_use');
if (!toolUseBlock) {
  throw new Error('No tool_use block in Claude response — the model did not call extract_account_risk_signal.');
}

const parsed = toolUseBlock.input;

// Add system metadata
parsed.last_updated = new Date().toISOString();
parsed.pipeline_version = '2.0';

// Enforce risk tier bucketing
const score = parsed.financial_risk_score || 0;
if (score >= 80) parsed.risk_tier = 'Critical';
else if (score >= 60) parsed.risk_tier = 'High';
else if (score >= 40) parsed.risk_tier = 'Medium';
else parsed.risk_tier = 'Low';

// Safety: cap revenue_at_risk to arr (can't be at risk of more than the contract)
if (parsed.revenue_at_risk > parsed.arr) parsed.revenue_at_risk = parsed.arr;

return [{ json: parsed }];
